export const getVerticesCoords = (polygon: Entity) => {
  const coords: Vector2d[] = [];
  const numberOfVertices = polygon.geometry.vertices; // Number of vertices in the polygon

  for (let i = 0; i < numberOfVertices; i++) {
    const theta = (Math.PI * 2 / numberOfVertices) * i;
    const vertex = {
      x: Math.cos(theta + polygon.geometry.angle) * polygon.geometry.radius + polygon.geometry.vec.x,
      y: Math.sin(theta + polygon.geometry.angle) * polygon.geometry.radius + polygon.geometry.vec.y
    };
    coords.push(vertex);
  }

  return coords;
