import { Entity } from "../main"

type Projection = {
  min: number;
  max: number;
}

export const getVerticesCoords = (polygon: Entity) => {
  const coords: Vector2d[] = []
  for (let i = 0; i < polygon.geometry.vertices; i++) {
    const theta = Math.PI * 2 / polygon.geometry.vertices * i
    coords.push({
      x: Math.cos(theta + polygon.geometry.angle) * 
        polygon.geometry.radius + polygon.geometry.vec.x,
      y: Math.sin(theta + polygon.geometry.angle) * 
        polygon.geometry.radius + polygon.geometry.vec.y
    })
  }
  return coords
}

const getCircleAxes = (circle: Entity, polygonVertices: Vector2d[]) => {
  const axes: Vector2d[] = []
  for (let i = 0; i < polygonVertices.length; i++) {
    axes.push(normalized({ 
      x: polygonVertices[i].x - circle.geometry.vec.x, 
      y: polygonVertices[i].y - circle.geometry.vec.y 
    }))
  }
  return axes
}

const getEdgeNormals = (verticesCoords: Vector2d[]) => {
  const edgeNormals: Vector2d[] = []
  for (let i = 0; i < verticesCoords.length; i++) {
    const p1 = verticesCoords[i]
    const p2 = verticesCoords[i + 1] || verticesCoords[0]
    const edge = {x: p2.x - p1.x, y: p2.y - p1.y}
    const norm = normalized(normal(edge))
    edgeNormals.push(norm)
  }
  return edgeNormals
}

const projectOnAxis = (verticesCoords: Vector2d[], axis: Vector2d): Projection => {
  let min = dotProduct(axis, verticesCoords[0])
  let max = min
  for (let i = 0; i < verticesCoords.length; i++) {
    const projection = dotProduct(axis, verticesCoords[i])
    if (projection < min) {
      min = projection
    } else if (projection > max) {
      max = projection
    }
  }
  return { min: min, max: max }
}

const checkProjectionOverlaps = 
  (projA: Projection, projB: Projection): number => {
  const overlapA = projA.min < projB.max && projA.min > projB.min
  const overlapB = projB.min < projA.max && projB.min > projA.min
  let magnitude = Infinity
  if (!overlapA && !overlapB)
    return magnitude
  if (overlapA)
    magnitude = projB.max - projA.min
  else if (overlapB)
    magnitude = projB.min - projA.max
  return magnitude
}

const twoPolygons = (polygonA: Entity, polygonB: Entity): Vector2d | false => {
  const veticesA = getVerticesCoords(polygonA)
  const veticesB = getVerticesCoords(polygonB)
  const axes = getEdgeNormals(veticesA).concat(getEdgeNormals(veticesB))
  let mtv: Vector2d = { x: Infinity, y: Infinity }
  for (let i = 0; i < axes.length; i++) {
    const projA = projectOnAxis(veticesA, axes[i])
    const projB = projectOnAxis(veticesB, axes[i])
    const mag = checkProjectionOverlaps(projA, projB)
    if (mag === Infinity)
      return false
    const vector = { x: axes[i].x * mag, y: axes[i].y * mag }
    if (magnitude(vector) < magnitude(mtv))
      mtv = vector
  }
  return mtv
}

const circleAndPolygon = (circle: Entity, polygon: Entity): Vector2d | false => {
  const polygonVertices = getVerticesCoords(polygon)
  const axes = getEdgeNormals(polygonVertices)
    .concat(getCircleAxes(circle, polygonVertices))
  let mtv = { x: Infinity, y: Infinity }
  for (let i = 0; i < axes.length; i++) {
    const dot = dotProduct(axes[i],
      { x: circle.geometry.vec.x, y: circle.geometry.vec.y })
    const projA = { 
      min: dot - circle.geometry.radius, 
      max: dot + circle.geometry.radius 
    }
    const projB = projectOnAxis(polygonVertices, axes[i])
    const mag = checkProjectionOverlaps(projA, projB)
    if (mag === Infinity)
      return false
    const vector = { x: axes[i].x * mag, y: axes[i].y * mag }
    if (magnitude(vector) < magnitude(mtv))
      mtv = vector
  }
  return mtv
}

const polygonAndCircle = (polygon: Entity, circle: Entity): Vector2d | false => {
  let mtv = circleAndPolygon(circle, polygon)
  if (!mtv)
    return false
  return { x: -mtv.x, y: -mtv.y }
}

const twoCircles = (circleA: Entity, circleB: Entity): Vector2d | false => {
  const distance = Math.pow(circleB.geometry.vec.x - circleA.geometry.vec.x, 2) 
    + Math.pow(circleA.geometry.vec.y - circleB.geometry.vec.y, 2)
  const radiusSumSquared = (circleA.geometry.radius + circleB.geometry.radius) ** 2
  const overlap = distance <= radiusSumSquared
  if (!overlap)
    return false
  const offset = Math.sqrt(radiusSumSquared) - Math.sqrt(distance)
  const vector = normalized({
    x: circleA.geometry.vec.x - circleB.geometry.vec.x, 
    y: circleA.geometry.vec.y - circleB.geometry.vec.y
  })
  const mtv: Vector2d = { x: vector.x * offset, y: vector.y * offset }
  return mtv
}

const separateEntities = (enA: Entity, enB: Entity, mtv: Vector2d) => {
  enA.geometry.vec.x += mtv.x 
  enA.geometry.vec.y += mtv.y 
  enB.geometry.vec.x -= mtv.x 
  enB.geometry.vec.y -= mtv.y 
}

export const checkCollisions = (entities: Entity[]) => {
  const len = entities.length
  for (let i = 0; i < len; i++) {
    const enA = entities[i]
    for (let j = i + 1; j < len; j++) {
      const enB = entities[j]
      let mtv: Vector2d | false = false
      if (enA.geometry.shape === "polygon" && enB.geometry.shape === "polygon")
        mtv = twoPolygons(enA, enB)
      else if (enA.geometry.shape === "circle" && enB.geometry.shape === "circle")
        mtv = twoCircles(enA, enB)
      else if (enA.geometry.shape === "circle" && enB.geometry.shape === "polygon")
        mtv = circleAndPolygon(enA, enB)
      else if (enA.geometry.shape === "polygon" && enB.geometry.shape === "circle")
        mtv = polygonAndCircle(enA, enB)
      if (mtv) {
        enA.visuals.activeColor = enA.visuals.collisionColor
        enB.visuals.activeColor = enB.visuals.collisionColor
        separateEntities(enA, enB, mtv)
      } 
    }
  }
}

The Minimum Translation Vector (MTV) from the Separating Axis Theorem (SAT) primarily tells you how far and in what direction one shape needs to be moved to resolve a collision with another shape. It does not directly tell you which side the collision occurred on, but with some additional logic, you can infer the side of the collision based on the MTV and the involved shapes' positions and velocities.

Here's how you might interpret the collision side using the MTV:

1. **Normalize the MTV**: Ensure that the MTV is normalized so that it's a unit vector representing the direction of the collision, not the depth. You will use this direction to determine the collision side.

2. **Relative Position and Velocity**: You might consider the objects' relative positions and their direction of movement (velocity). For example, if object A is moving to the right and collides with object B, you can infer a collision on A's right side.

3. **Dot Product**: Use the dot product between the normalized MTV and a direction vector of an entity to determine the side of the collision.
   - For instance, if you have standard directional vectors (up, down, left, right), you can take the dot product of the normalized MTV with each of these vectors. The highest absolute value of the dot product likely corresponds to the side of the collision.

Here's a basic example of interpreting the side using the MTV in pseudo-code:

```javascript
// Assuming `mtv` is the Minimum Translation Vector and `velocity` is the entity's velocity vector

// Dot products for each cardinal direction
let up = { x: 0, y: -1 }; // up direction vector
let down = { x: 0, y: 1 }; // down direction vector
let left = { x: -1, y: 0 }; // left direction vector
let right = { x: 1, y: 0 }; // right direction vector

let upDot = dotProduct(normalize(mtv), up);
let downDot = dotProduct(normalize(mtv), down);
let leftDot = dotProduct(normalize(mtv), left);
let rightDot = dotProduct(normalize(mtv), right);

// Interpret collision side based on which direction has the highest dot product with MTV
let side;
if (Math.abs(upDot) > Math.abs(downDot) && Math.abs(upDot) > Math.abs(leftDot) && Math.abs(upDot) > Math.abs(rightDot)) {
    side = "Up";
} else if (Math.abs(downDot) > Math.abs(leftDot) && Math.abs(downDot) > Math.abs(rightDot)) {
    side = "Down";
} else if (Math.abs(leftDot) > Math.abs(rightDot)) {
    side = "Left";
} else {
    side = "Right";
}

// Consider velocity for final determination if needed
if (velocity.x === 0 && velocity.y === 0) {
